//-------------------------------------------------------------------------
// 엑셀 Download
//-------------------------------------------------------------------------
scwin.f_Excel = async function() {
    if (ds_susRecvList.getRowCount() == 0) {
        await $c.win.alert(MSG_CM_WRN_002);
        return;
    }

    let fileName = '원화채권정리';

    if (await $c.win.confirm("Excel로 다운로드 하시겠습니까?")) {
        await $c.data.downloadGridViewExcel(gr_susRecvList, { fileName: fileName + ".xlsx", sheetName: fileName });
    }
};

